class Solution:
    def maxValue(self, events, k):
        events = sorted(events)
        n = len(events)
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(10000)

        def nxt(i):
            end = events[i][1]
            lo, hi = i + 1, n
            while lo < hi:
                mid = (lo + hi) // 2
                if events[mid][0] > end:
                    hi = mid
                else:
                    lo = mid + 1
            return lo

        @lru_cache(maxsize=None)
        def solve(i, j):
            if i >= n or j == 0:
                return 0
            skip = solve(i + 1, j)
            take = events[i][2] + solve(nxt(i), j - 1)
            return max(skip, take)

        res = solve(0, k)
        solve.cache_clear()
        return res

