var maxValue = function(events, k) {
    events.sort((a, b) => a[0] - b[0]);
    const n = events.length;
    const starts = events.map(e => e[0]);
    const upper = (x) => {
        let lo = 0, hi = n;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (starts[mid] > x) hi = mid; else lo = mid + 1;
        }
        return lo;
    };
    const nxt = events.map(e => upper(e[1]));
    const dp = Array.from({length: n + 1}, () => new Array(k + 1).fill(0));
    for (let i = n - 1; i >= 0; i--) {
        for (let j = 1; j <= k; j++) {
            const skip = dp[i + 1][j];
            const take = events[i][2] + dp[nxt[i]][j - 1];
            dp[i][j] = Math.max(skip, take);
        }
    }
    return dp[0][k];
};
